function ModelDreamSchool:OnModelInit()
    self._cfgType = ModelDreamSchool.DISTINGUISH_TYPE_1
    self:ModelNetMsgRecv(LProtoIds.SchoolInfoListResp,function (...) self:OnSchoolInfoListResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.SchoolInfoChangeResp,function (...) self:OnSchoolInfoChangeResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.SchoolGoalRewardResp,function (...) self:OnSchoolGoalRewardResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.SchoolAcceptQuestResp,function (...) self:OnSchoolAcceptQuestResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.SchoolRewardNoticeInfoListResp,function (...) self:OnSchoolRewardNoticeInfoListResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.SchoolGiftDailyResp,function (...)self:OnSchoolGiftDailyResp(...) end)
    self:ModelEventRecv(EventNames.ON_TIME_ZERO,function () self:OnSchoolInfoListReq() end)
end


--在协议数据处理完之后需要调用finish
function ModelDreamSchool:OnModelRequest()
    self:OnSchoolInfoListReq()
    self:ModelFinish()
end

