---resp
function ModelDreamSchool:OnSchoolInfoListResp(pb)--返回梦境学院数据
    local schoolInfos = pb.schoolInfos
    local type = pb.type or 1
    self._cfgType = type
    self._giftDaily = pb.giftDaily
    self:SetSchoolInfos(schoolInfos)
end

function ModelDreamSchool:OnSchoolInfoChangeResp(pb)--更新梦境学院数据，服务端下发变更的数据
    local schoolInfos = pb.schoolInfos
    self:SetSchoolInfos(schoolInfos)
end

function ModelDreamSchool:OnSchoolGoalRewardResp(pb)--返回领取目标奖励
    local refId = pb.refId
    local bagReward = pb.bagReward
    self._goalRewards[refId] = refId

    if bagReward > 0 then
        local t =
        {
            refId = 52901,
            func = function (...) gModelPlayerSpace:OpenSpaceWnd(gModelPlayer:GetPlayerId(),3,3) end,
            ignoreWnd = true
        }
        gModelGeneral:InsertPopWndPara(t)
    end
end

function ModelDreamSchool:OnSchoolAcceptQuestResp(pb)--返回接受限时任务

end

function ModelDreamSchool:OnSchoolRewardNoticeInfoListResp(pb)--领取奖励公告返回
    local notices = pb.notices
    self._notices = {}
    for i, v in ipairs(notices) do
        local log = {
            playerName = v.playerName,--玩家名
            targetId = v.targetId,--奖励表RefId
            isGoalReward = v.isGoalReward,--是否包含大奖 1表示有 0表示无
        }
        table.insert(self._notices,log)
    end
end

function ModelDreamSchool:OnSchoolGiftDailyReq()
    local pb = LProtoHelper.CreateProto(LProtoIds.SchoolGiftDailyReq)
    SendMessage(pb,LProtoIds.SchoolGiftDailyReq)
end
function ModelDreamSchool:OnSchoolGiftDailyResp(pb)
    self._giftDaily = 0
end
------------------------------获取数据------------------------------------
function ModelDreamSchool:GetGiftDaily()
    return self._giftDaily or 0
end
function ModelDreamSchool:SetSchoolInfos(schoolInfos)--设置梦境学院数据
    local _schoolInfos = self._schoolInfos or {}
    local _goalRewards = self._goalRewards or {}
    for i, v in ipairs(schoolInfos) do
        local info = StructSchoolInfo:New()
        info:CreateByPb(v)
        _schoolInfos[info.refId] = info
        _goalRewards = self:SetGoalRewards(_goalRewards,info.goalRewards)
    end
    self._schoolInfos = _schoolInfos
    self._goalRewards = _goalRewards

end

function ModelDreamSchool:SetGoalRewards(list,rewards)
    local list = list or {}
    if rewards then
        for i, v in ipairs(rewards) do
            list[v] = v
        end
    end
    return list
end

function ModelDreamSchool:GetSchoolInfos()--获取梦境学院数据
    return self._schoolInfos or {}
end

function ModelDreamSchool:GetNotices()
    return self._notices or {}
end

function ModelDreamSchool:GetIsGetGoalRewardByRefId(refId)--获取是否领取了目标奖励
    local _goalRewards = self._goalRewards or {}
    return _goalRewards[refId]
end
----------------------------获取表数据------------------------------------
function ModelDreamSchool:GetSchoolThemeRef()
    local list = {}
    for i, v in pairs(GameTable.AcademyThemeRef) do
        table.insert(list,v)
    end
    table.sort(list,function (a,b)
        return a.refId < b.refId
    end)
    return list
end

function ModelDreamSchool:GetSchoolConfigRefByKey(key)
    return GameTable.AcademyConfigRef[key]
end

function ModelDreamSchool:GetSchoolThemeRefByRefId(refId)
    return GameTable.AcademyThemeRef[refId]
end

