function ModelDreamSchool:GetSchoolRankRewardByTheme(theme)
    -- 【G公共支持】删除梦境学院的相关临时机制
    -- local type = self:GetConfigType()
    -- local isOneReward = type == 2

    local list = {}
    for i, v in pairs(GameTable.AcademyRankRef) do
        if theme == v.type then
            -- 【G公共支持】删除梦境学院的相关临时机制
            -- local rewardStr = isOneReward and v.reward2 or v.reward
            local rewardStr = v.reward
            if not string.isempty(rewardStr) then
                local items = LxDataHelper.ParseItem(rewardStr)
                local data = {
                    refId = v.refId,
                    type  = v.type,
                    sort = v.sort,
                    rank = v.rank,
                    reward = items,
                }
                table.insert(list,data)
            end
        end
    end
    table.sort(list , function (a,b)
        return a.sort < b.sort
    end)
    return list
end

function ModelDreamSchool:GetSchoolTargetRefs()
    local questRefs
    if self._cfgType == ModelDreamSchool.DISTINGUISH_TYPE_1 then
        questRefs = GameTable.AcademyTargetRef
    else
        questRefs = GameTable.SchoolTarget2Ref
    end
    return questRefs
end

function ModelDreamSchool:GetStageEndByThemeStage(theme,stage)
    local questRefs = self:GetSchoolTargetRefs()
    for i, v in pairs(questRefs) do
        if v.theme == theme and v.stage == stage and v.stageEnd == 1 then
            return v
        end
    end
    return nil
end

function ModelDreamSchool:GetSchoolTargetRefByType(type,stage)
    local list = {}
    local questRefs = self:GetSchoolTargetRefs()

    for i, v in pairs(questRefs) do
        if v.theme == type and (not stage or v.stage == stage) then
            table.insert(list,v)
        end
    end
    table.sort(list,function (a,b)
        return a.refId < b.refId
    end)
    return list
end

function ModelDreamSchool:GetSchoolTargetRefByRefId(refId)
    local questRefs = self:GetSchoolTargetRefs()
    return questRefs[refId]
end

function ModelDreamSchool:SchoolThemeQuestRefs()
    local questRefs
    if self._cfgType == ModelDreamSchool.DISTINGUISH_TYPE_1 then
        questRefs = GameTable.AcademyThemeQuestRef
    else
        questRefs = GameTable.SchoolThemeQuest2Ref
    end
    return questRefs
end

function ModelDreamSchool:GetSchoolThemeQuestRefByRefId(refId)
    local questRefs = self:SchoolThemeQuestRefs()
    return questRefs[refId]
end

function ModelDreamSchool:GetSchoolThemeQuestRefs(type)
    local list = {}
    local questRefs = self:SchoolThemeQuestRefs()

    for i, v in pairs(questRefs) do
        if type == v.themeType then
            table.insert(list,v)
        end
    end
    table.sort(list,function (a,b)
        return a.sort < b.sort
    end)
    return list
end

function ModelDreamSchool:CheckShowRank(refId)
    local schoolInfo = self._schoolInfos and self._schoolInfos[refId]
    if not schoolInfo then
        return false
    end
    local showRankTime = schoolInfo.startRankTime or 0
    return GetTimestamp() >= showRankTime/1000
end
